const body = $input.first().json;

// Superchat Trigger payload structure:
// body.message.content.body = message text
// body.message.from.identifier = phone number
// body.message.from.id = contact ID
// body.message.to.channel_id = channel ID
// body.message.conversation_id = conversation ID

const message = body.message?.content?.body || body.payload?.message?.body || '';
const contactId = body.message?.from?.id || body.payload?.contact?.id || '';
const contactName = body.message?.from?.name || body.payload?.contact?.name || 'Unbekannt';
const contactPhone = body.message?.from?.identifier || body.payload?.contact?.phone || '';
const channel = body.message?.to?.channel_type || body.payload?.channel?.type || 'whatsapp';
const channelId = body.message?.to?.channel_id || body.payload?.channel?.id || '';
const conversationId = body.message?.conversation_id || body.payload?.conversation?.id || '';

const ADMIN_PHONES = ['4915129783774'];
const isAdmin = ADMIN_PHONES.some(p => contactPhone.includes(p));

let messageType = 'customer_question';
if (isAdmin && message.toLowerCase().includes('offene fragen')) {
  messageType = 'admin_list_questions';
} else if (isAdmin && message.toLowerCase().startsWith('antwort:')) {
  messageType = 'admin_answer';
}

return [{ json: { message, contactId, contactName, contactPhone, channel, channelId, conversationId, isAdmin, messageType } }];

const results = $('Search Knowledge Base').all().map(item => item.json);
const historyRows = $('Fetch History').all().map(item => item.json);
const message = $('Route Message').first().json.message;
const contactName = $('Route Message').first().json.contactName;
const contactPhone = $('Route Message').first().json.contactPhone;
const channelId = $('Route Message').first().json.channelId;
const conversationId = $('Route Message').first().json.conversationId;

// Build knowledge context
let context = '';
let hasGoodMatch = false;
if (results.length > 0 && results[0].similarity) {
  hasGoodMatch = results[0].similarity > 0.5;
  context = results
    .filter(r => r.similarity > 0.3)
    .map(r => '[' + (r.category || 'Allgemein') + '] ' + (r.title || '') + ':\n' + r.content)
    .join('\n\n---\n\n');
}

// Build conversation history (reverse to chronological order)
let chatHistory = '';
if (historyRows.length > 0) {
  const sorted = historyRows.reverse();
  chatHistory = sorted
    .map(r => (r.role === 'user' ? 'Kunde' : 'Bauloewen-Assistent') + ': ' + r.content)
    .join('\n');
}

return [{
  json: {
    message,
    contactName,
    contactPhone,
    channelId,
    conversationId,
    context,
    chatHistory,
    hasGoodMatch,
    resultCount: results.filter(r => r.similarity > 0.3).length
  }
}];

const response = $input.first().json;
let text = response.content?.[0]?.text || response.text || response.message || '';
const conversationId = $('Prepare Context').first().json.conversationId;
const contactPhone = $('Prepare Context').first().json.contactPhone;
const channelId = $('Prepare Context').first().json.channelId;
const message = $('Prepare Context').first().json.message;
const contactName = $('Prepare Context').first().json.contactName;
const hasGoodMatch = $('Prepare Context').first().json.hasGoodMatch;
const isUncertain = text.startsWith('[UNSICHER]');
text = text.replace('[UNSICHER]', '').trim();
return [{ json: { replyText: text, conversationId, contactPhone, channelId, originalQuestion: message, contactName, isUncertain, hasGoodMatch } }];

const questions = $input.all().map(item => item.json);
const contactPhone = $('Route Message').first().json.contactPhone;
const channelId = $('Route Message').first().json.channelId;
let reply = '';
if (questions.length === 0) {
  reply = 'Keine offenen Fragen!';
} else {
  reply = questions.length + ' offene Fragen:\n\n';
  questions.forEach((q, i) => {
    const date = new Date(q.created_at).toLocaleDateString('de-DE');
    reply += (i + 1) + '. [' + q.id.substring(0, 8) + '] ' + q.question + ' (' + date + ')\n\n';
  });
  reply += 'Zum Beantworten schreibe:\nAntwort: [ID] Deine Antwort';
}
return [{ json: { replyText: reply, contactPhone, channelId } }];

const message = $('Route Message').first().json.message;
const contactPhone = $('Route Message').first().json.contactPhone;
const channelId = $('Route Message').first().json.channelId;
const match = message.match(/^antwort:\s*\[?([a-f0-9-]+)\]?\s+(.+)$/is);
if (!match) {
  return [{ json: { error: true, replyText: 'Format: Antwort: [ID] Deine Antwort', contactPhone, channelId } }];
}
return [{ json: { questionId: match[1], answer: match[2].trim(), contactPhone, channelId, error: false } }];

const result = $input.first().json;
const contactPhone = $('Parse Answer').first().json.contactPhone;
const channelId = $('Parse Answer').first().json.channelId;
const reply = result.question ? 'Gelernt!

Frage: ' + result.question + '
Antwort: ' + result.answer + '

Der Bot kann das jetzt selbst beantworten.' : 'Frage nicht gefunden.';
return [{ json: { replyText: reply, contactPhone, channelId } }];

